#!/usr/bin/env python3
"""
Dependency Lock Management Guide + Helper Script

This file serves two purposes:
1) Documentation for best practices to keep Python dependencies consistent across dev/prod.
2) A helper CLI to generate/update lock artifacts:
   - requirements.txt with hashes (pip-tools)
   - Poetry lock files (poetry.lock)

================================================================================
GOALS
================================================================================
- Deterministic installs: same versions in development, CI, and production.
- Reproducible builds: lock files committed to VCS.
- Safe upgrades: controlled updates with reviewable diffs.
- Security: hashed requirements for pip, and routine vulnerability scanning.

================================================================================
RECOMMENDED APPROACHES
================================================================================

A) pip + pip-tools (requirements.in -> requirements.txt with hashes)
---------------------------------------------------------------
Use when:
- You deploy with pip.
- You want requirements.txt compatible with many environments.
- You want hash-checking mode for tamper protection.

Files:
- requirements.in      (top-level direct deps only; unpinned or loosely pinned)
- requirements-dev.in  (dev/test tooling; includes requirements.in)
- requirements.txt     (compiled, pinned, includes transitive deps, with hashes)
- requirements-dev.txt (compiled dev lock; includes requirements.txt)

Typical workflow:
1) Add/update a dependency:
   - Edit requirements.in (or requirements-dev.in for tooling)
2) Compile lock:
   - pip-compile --generate-hashes --resolver=backtracking -o requirements.txt requirements.in
   - pip-compile --generate-hashes --resolver=backtracking -o requirements-dev.txt requirements-dev.in
3) Install:
   - pip install --require-hashes -r requirements.txt
   - pip install --require-hashes -r requirements-dev.txt

Update strategies:
- Patch/minor updates (safe-ish):
  - pip-compile --upgrade --generate-hashes ...
- Update a single package:
  - pip-compile --upgrade-package <name> --generate-hashes ...
- Keep Python version consistent:
  - Use a consistent interpreter in CI (e.g., 3.11.x) and compile with that.

Best practices:
- Keep requirements.in minimal (only direct dependencies).
- Prefer constraints in .in (e.g., "requests>=2.31,<3") rather than pinning everything.
- Commit compiled .txt locks.
- Use --require-hashes in production installs.
- Consider separate locks per Python version if you support multiple.

B) Poetry (pyproject.toml + poetry.lock)
----------------------------------------
Use when:
- You want Poetry's dependency resolution and packaging workflow.
- You deploy using Poetry or export requirements for pip.

Files:
- pyproject.toml  (declares direct dependencies, version ranges)
- poetry.lock     (locked transitive dependency graph)

Typical workflow:
1) Add dependency:
   - poetry add <package>
   - poetry add --group dev <package>   (for dev dependencies)
2) Update lock without changing constraints:
   - poetry lock
3) Update dependencies within allowed ranges:
   - poetry update
   - poetry update <package>
4) Install:
   - poetry install --sync

Export for pip deployments:
- poetry export -f requirements.txt --with-hashes -o requirements.txt
- poetry export -f requirements.txt --with dev --with-hashes -o requirements-dev.txt
(Flags may vary by Poetry version; verify in CI.)

Best practices:
- Commit poetry.lock.
- Use poetry install --sync in CI to ensure environment matches lock exactly.
- Keep Python version consistent across environments.

================================================================================
CONSISTENCY ACROSS DEV/PROD
================================================================================
- Build and run with the same lock file.
- Use the same Python major/minor version (and ideally patch) in dev/CI/prod.
- Prefer containerized builds or pinned toolchain versions:
  - pip-tools version pinned (e.g., in requirements-dev.in or a tools lock)
  - Poetry version pinned (e.g., in CI and dev docs)
- Always regenerate lock files in CI checks when dependency specs change, or at least
  validate they are up-to-date.

Suggested CI checks:
- For pip-tools:
  - Re-run pip-compile and fail if diff exists (lock out-of-date).
  - pip install --require-hashes -r requirements.txt
- For Poetry:
  - poetry lock --check (or equivalent)
  - poetry install --sync
  - optionally poetry export and diff if you deploy via pip

================================================================================
SECURITY & MAINTENANCE
================================================================================
- Run periodic upgrades (e.g., weekly) and review diffs.
- Scan:
  - pip-audit -r requirements.txt
  - safety check (if used)
  - poetry audit (if available)
- Remove unused dependencies regularly.

================================================================================
SCRIPT USAGE
================================================================================
This script automates common tasks and standardizes commands.

Examples:
- pip-tools compile (prod + dev):
  ./dep_lock.py piptools-compile

- pip-tools upgrade all:
  ./dep_lock.py piptools-upgrade

- pip-tools upgrade a single package:
  ./dep_lock.py piptools-upgrade --package requests

- Poetry lock:
  ./dep_lock.py poetry-lock

- Poetry update:
  ./dep_lock.py poetry-update --package requests

- Poetry export requirements with hashes:
  ./dep_lock.py poetry-export

- Validate tool availability and show versions:
  ./dep_lock.py doctor

Notes:
- The script assumes conventional filenames:
  requirements.in, requirements-dev.in, requirements.txt, requirements-dev.txt
- Adjust defaults with CLI flags.

================================================================================
"""

from __future__ import annotations

import argparse
import os
import platform
import shutil
import subprocess
import sys
from dataclasses import dataclass
from typing import Iterable, Optional


@dataclass(frozen=True)
class Paths:
    requirements_in: str = "requirements.in"
    requirements_dev_in: str = "requirements-dev.in"
    requirements_txt: str = "requirements.txt"
    requirements_dev_txt: str = "requirements-dev.txt"
    pyproject: str = "pyproject.toml"
    poetry_lock: str = "poetry.lock"


def _which(cmd: str) -> Optional[str]:
    return shutil.which(cmd)


def _run(cmd: list[str], *, check: bool = True, env: Optional[dict[str, str]] = None) -> int:
    print("+", " ".join(cmd))
    p = subprocess.run(cmd, check=False, env=env)
    if check and p.returncode != 0:
        raise SystemExit(p.returncode)
    return p.returncode


def _tool_version(tool: str) -> str:
    path = _which(tool)
    if not path:
        return "not found"
    try:
        out = subprocess.check_output([tool, "--version"], stderr=subprocess.STDOUT, text=True).strip()
        return out or "unknown"
    except Exception:
        return "unknown"


def _exists(path: str) -> bool:
    return os.path.exists(path)


def _require_file(path: str) -> None:
    if not _exists(path):
        raise SystemExit(f"Missing required file: {path}")


def _optional_file_hint(path: str, hint: str) -> None:
    if not _exists(path):
        print(f"Note: {path} not found. {hint}")


def piptools_compile(
    paths: Paths,
    *,
    python: str,
    generate_hashes: bool,
    resolver: str,
    extra_args: list[str],
) -> None:
    _require_file(paths.requirements_in)
    _optional_file_hint(
        paths.requirements_dev_in,
        f"Create it if you want a dev lock. Common content:\n  -r {paths.requirements_in}\n  pytest\n  black\n",
    )

    pip_compile = _which("pip-compile")
    if not pip_compile:
        raise SystemExit("pip-compile not found. Install pip-tools: python -m pip install pip-tools")

    base_cmd = ["pip-compile", f"--python-executable={python}", f"--resolver={resolver}"]
    if generate_hashes:
        base_cmd.append("--generate-hashes")

    cmd_prod = base_cmd + ["-o", paths.requirements_txt, paths.requirements_in] + extra_args
    _run(cmd_prod)

    if _exists(paths.requirements_dev_in):
        cmd_dev = base_cmd + ["-o", paths.requirements_dev_txt, paths.requirements_dev_in] + extra_args
        _run(cmd_dev)


def piptools_upgrade(
    paths: Paths,
    *,
    python: str,
    generate_hashes: bool,
    resolver: str,
    package: Optional[str],
    extra_args: list[str],
) -> None:
    _require_file(paths.requirements_in)

    pip_compile = _which("pip-compile")
    if not pip_compile:
        raise SystemExit("pip-compile not found. Install pip-tools: python -m pip install pip-tools")

    base_cmd = ["pip-compile", f"--python-executable={python}", f"--resolver={resolver}"]
    if generate_hashes:
        base_cmd.append("--generate-hashes")

    if package:
        base_cmd += ["--upgrade-package", package]
    else:
        base_cmd.append("--upgrade")

    cmd_prod = base_cmd + ["-o", paths.requirements_txt, paths.requirements_in] + extra_args
    _run(cmd_prod)

    if _exists(paths.requirements_dev_in):
        cmd_dev = base_cmd + ["-o", paths.requirements_dev_txt, paths.requirements_dev_in] + extra_args
        _run(cmd_dev)


def pip_install_locked(paths: Paths, *, require_hashes: bool, dev: bool) -> None:
    req = paths.requirements_dev_txt if dev else paths.requirements_txt
    _require_file(req)

    cmd = [sys.executable, "-m", "pip", "install"]
    if require_hashes:
        cmd.append("--require-hashes")
    cmd += ["-r", req]
    _run(cmd)


def poetry_lock(paths: Paths, *, extra_args: list[str]) -> None:
    _require_file(paths.pyproject)
    poetry = _which("poetry")
    if not poetry:
        raise SystemExit("poetry not found. Install Poetry and ensure it's on PATH.")
    _run(["poetry", "lock"] + extra_args)


def poetry_update(paths: Paths, *, package: Optional[str], extra_args: list[str]) -> None:
    _require_file(paths.pyproject)
    poetry = _which("poetry")
    if not poetry:
        raise SystemExit("poetry not found. Install Poetry and ensure it's on PATH.")
    cmd = ["poetry", "update"]
    if package:
        cmd.append(package)
    cmd += extra_args
    _run(cmd)


def poetry_install(paths: Paths, *, sync: bool, extra_args: list[str]) -> None:
    _require_file(paths.pyproject)
    poetry = _which("poetry")
    if not poetry:
        raise SystemExit("poetry not found. Install Poetry and ensure it's on PATH.")
    cmd = ["poetry", "install"]
    if sync:
        cmd.append("--sync")
    cmd += extra_args
    _run(cmd)


def poetry_export(
    paths: Paths,
    *,
    output: str,
    dev: bool,
    with_hashes: bool,
    extra_args: list[str],
) -> None:
    _require_file(paths.pyproject)
    poetry = _which("poetry")
    if not poetry:
        raise SystemExit("poetry not found. Install Poetry and ensure it's on PATH.")

    cmd = ["poetry", "export", "-f", "requirements.txt"]
    if dev:
        cmd += ["--with", "dev"]
    if with_hashes:
        cmd.append("--with-hashes")
    cmd += ["-o", output]
    cmd += extra_args
    _run(cmd)


def doctor(paths: Paths) -> None:
    print("System:")
    print("  python:", sys.version.replace("\n", " "))
    print("  executable:", sys.executable)
    print("  platform:", platform.platform())
    print()
    print("Tools:")
    print("  pip:", _tool_version("pip"))
    print("  pip-compile:", _tool_version("pip-compile"))
    print("  poetry:", _tool_version("poetry"))
    print()
    print("Project files:")
    for p in [
        paths.requirements_in,
        paths.requirements_dev_in,
        paths.requirements_txt,
        paths.requirements_dev_txt,
        paths.pyproject,
        paths.poetry_lock,
    ]:
        print(f"  {p}: {'present' if _exists(p) else 'missing'}")


def _parse_args(argv: list[str]) -> argparse.Namespace:
    p = argparse.ArgumentParser(prog="dep_lock.py", description="Manage Python dependency lock files (pip-tools / Poetry).")

    p.add_argument("--requirements-in", default="requirements.in")
    p.add_argument("--requirements-dev-in", default="requirements-dev.in")
    p.add_argument("--requirements-txt", default="requirements.txt")
    p.add_argument("--requirements-dev-txt", default="requirements-dev.txt")
    p.add_argument("--pyproject", default="pyproject.toml")
    p.add_argument("--poetry-lock", default="poetry.lock")

    sub = p.add_subparsers(dest="cmd", required=True)

    s = sub.add_parser("doctor", help="Show environment/tool versions and expected project files.")
    s.set_defaults(fn=lambda ns, paths: doctor(paths))

    s = sub.add_parser("piptools-compile", help="Compile requirements.txt (+ requirements-dev.txt if dev input exists).")
    s.add_argument("--python", default=sys.executable, help="Python executable used for resolution.")
    s.add_argument("--no-hashes", action="store_true", help="Do not generate hashes (not recommended for production).")
    s.add_argument("--resolver", default="backtracking", choices=["backtracking", "legacy"])
    s.add_argument("extra", nargs=argparse.REMAINDER, help="Extra args passed to pip-compile after '--'.")
    s.set_defaults(
        fn=lambda ns, paths: piptools_compile(
            paths,
            python=ns.python,
            generate_hashes=not ns.no_hashes,
            resolver=ns.resolver,
            extra_args=_strip_double_dash(ns.extra),
        )
    )

    s = sub.add_parser("piptools-upgrade", help="Upgrade all or one package, then recompile locks.")
    s.add_argument("--python", default=sys.executable, help="Python executable used for resolution.")
    s.add_argument("--package", help="Upgrade only this package (name as in requirements.in).")
    s.add_argument("--no-hashes", action="store_true", help="Do not generate hashes (not recommended for production).")
    s.add_argument("--resolver", default="backtracking", choices=["backtracking", "legacy"])
    s.add_argument("extra", nargs=argparse.REMAINDER, help="Extra args passed to pip-compile after '--'.")
    s.set_defaults(
        fn=lambda ns, paths: piptools_upgrade(
            paths,
            python=ns.python,
            generate_hashes=not ns.no_hashes,
            resolver=ns.resolver,
            package=ns.package,
            extra_args=_strip_double_dash(ns.extra),
        )
    )

    s = sub.add_parser("pip-install", help="Install from compiled requirements.txt (optionally dev).")
    s.add_argument("--dev", action="store_true", help="Install dev lock (requirements-dev.txt).")
    s.add_argument("--no-require-hashes", action="store_true", help="Do not enforce hashes.")
    s.set_defaults(
        fn=lambda ns, paths: pip_install_locked(paths, require_hashes=not ns.no_require_hashes, dev=ns.dev)
    )

    s = sub.add_parser("poetry-lock", help="Run 'poetry lock'.")
    s.add_argument("extra", nargs=argparse.REMAINDER, help="Extra args passed to poetry after '--'.")
    s.set_defaults(fn=lambda ns, paths: poetry_lock(paths, extra_args=_strip_double_dash(ns.extra)))

    s = sub.add_parser("poetry-update", help="Run 'poetry update' (optionally for one package).")
    s.add_argument("--package", help="Update only this package.")
    s.add_argument("extra", nargs=argparse.REMAINDER, help="Extra args passed to poetry after '--'.")
    s.set_defaults(fn=lambda ns, paths: poetry_update(paths, package=ns.package, extra_args=_strip_double_dash(ns.extra)))

    s = sub.add_parser("poetry-install", help="Run 'poetry install' (optionally --sync).")
    s.add_argument("--sync", action="store_true", help="Use --sync to match lock exactly.")
    s.add_argument("extra", nargs=argparse.REMAINDER, help="Extra args passed to poetry after '--'.")
    s.set_defaults(fn=lambda ns, paths: poetry_install(paths, sync=ns.sync, extra_args=_strip_double_dash(ns.extra)))

    s = sub.add_parser("poetry-export", help="Export requirements.txt from Poetry (optionally dev) with hashes.")
    s.add_argument("--output", default="requirements.txt", help="Output filename.")
    s.add_argument("--dev", action="store_true", help="Include dev dependencies.")
    s.add_argument("--no-hashes", action="store_true", help="Do not include hashes.")
    s.add_argument("extra", nargs=argparse.REMAINDER, help="Extra args passed to poetry after '--'.")
    s.set_defaults(
        fn=lambda ns, paths: poetry_export(
            paths,
            output=ns.output,
            dev=ns.dev,
            with_hashes=not ns.no_hashes,
            extra_args=_strip_double_dash(ns.extra),
        )
    )

    return p.parse_args(argv)


def _strip_double_dash(args: list[str]) -> list[str]:
    if args and args[0] == "--":
        return args[1:]
    return args


def main(argv: Optional[Iterable[str]] = None) -> int:
    ns = _parse_args(list(argv) if argv is not None else sys.argv[1:])
    paths = Paths(
        requirements_in=ns.requirements_in,
        requirements_dev_in=ns.requirements_dev_in,
        requirements_txt=ns.requirements_txt,
        requirements_dev_txt=ns.requirements_dev_txt,
        pyproject=ns.pyproject,
        poetry_lock=ns.poetry_lock,
    )
    ns.fn(ns, paths)
    return 0


if __name__ == "__main__":
    raise SystemExit(main())